using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

var services = new ServiceCollection()
    .AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning))
    .AddSingleton(new OpenAIClient(apiKey))
    .AddChatClient(b => b.Use(sp =>
        sp.GetRequiredService<OpenAIClient>().GetChatClient(modelId).AsIChatClient()))
    .AddSingleton<Notebook>()
    .AddSingleton<WebSearchTool>()
    .BuildServiceProvider();

var chatClient = services.GetRequiredService<IChatClient>();
var notebook   = services.GetRequiredService<Notebook>();
var webSearch  = services.GetRequiredService<WebSearchTool>();
var loggerFactory = services.GetRequiredService<ILoggerFactory>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic the user provides.

    Follow this workflow:
    1. Break the topic into 2-3 specific search queries.
    2. Use the SearchWeb tool for each query to gather information.
    3. As you find key facts, use the AddNote tool to save each important finding.
    4. After searching, use the GetNotes tool to review all your collected notes.
    5. Produce a well-structured summary that synthesizes your findings. Include the
       sources you found.

    Be thorough but concise. Cite sources when possible.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking",
    tools: tools,
    loggerFactory: loggerFactory);

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research this topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine("━━━ Research Summary ━━━\n");
Console.WriteLine(response.Text);

if (response.Usage is { } usage)
{
    Console.WriteLine($"\n📊 Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}");
}

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>Simulated web search tool that returns results for a query.</summary>
public sealed class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(10),
    };

    [Description("Search the web for information on a query. Returns a list of result snippets with source URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        // Use DuckDuckGo Instant Answer API (no key required, returns JSON)
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await Http.GetStringAsync(url, cancellationToken);
            using var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main summary)
            var abs = root.GetProperty("Abstract").GetString();
            var absUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abs))
                results.Add($"[Summary] {abs} (source: {absUrl})");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var link = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add($"- {text} (source: {link})");
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No detailed results found for '{query}'. Try a more specific query.";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }
}

/// <summary>Simple in-memory notebook for collecting research findings.</summary>
public sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record key facts, findings, or quotes discovered during research.")]
    public string AddNote(
        [Description("The note content to save")] string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

